<template>
  <div class="flex-direction-column">
    <div
      class="g-page-container-with-header"
      v-for="switchbutton in sortedSwitchbuttonData"
      :key="switchbutton.devid"
    >
      <div class="container-header flex-space-between">
        <span class="title">{{ switchbutton.devdesp }}</span>
        <div class="g-button" @click="handleRefreshRow(switchbutton)">更新</div>
      </div>

      <div class="container-content">
        <div class="g-kv-pair" v-for="(label, key) in displayLabels" :key="key">
          <div class="label">{{ label }}</div>
          <div
            class="value"
            :style="
              key === 'status'
                ? getStatusTextStyle(getDisplayValue(switchbutton, key))
                : {}
            "
          >
            {{ getDisplayValue(switchbutton, key) }}
          </div>
        </div>
      </div>
    </div>
  </div>
</template>

<script setup>
import { computed, watch } from 'vue'
import { storeToRefs } from 'pinia'
import { useWslStore } from '@/store/modules/ws.js'
import { useCommand } from '@/hooks/useCommand.js'
import { useDataMerge } from '@/hooks/useDataMerge'
import { useTimeFormat } from '@/hooks/useTimeFormat'
const { formatTimestamp } = useTimeFormat()

const store = useWslStore()
const { received, isConnected } = storeToRefs(store)
const { sendGetStatusData } = useCommand(store)

import { useStatus } from '@/hooks/useStatus'
const { getStatusTextStyle } = useStatus()

import { useSortData } from '@/hooks/useSortData'

// 显示标签映射
const displayLabels = {
  devid: '设备ID',
  devname: '设备名称',
  devtype: '设备类型',
  devdesp: '设备描述',
  timestamp: '时间',
  status: '状态'
}

// 获取开关数据，兼容13和61命令
const switchbuttonData = useDataMerge(
  computed(() => {
    const data = received.value?.statusData?.switchDataList
    if (!data || data.length === 0) {
      return [
        {
          devdesp: '暂无'
        }
      ]
    }
    return data
  })
).mergedData

const sortedSwitchbuttonData = useSortData(switchbuttonData, {
  key: 'devid',
  type: 'number',
  order: 'asc'
}).sortedData

const getDisplayValue = (item, key) => {
  let value = item[key]
  if (key === 'timestamp' && value) {
    value = formatTimestamp(value)
  }
  return value === null || value === undefined || value === '' ? '-' : value
}

// 单行刷新处理
const handleRefreshRow = (item) => {
  if (item.devid) {
    sendGetStatusData('switch', item.devid)
  }
}

// 等socket连接后发送13命令获取数据
watch(
  () => isConnected.value,
  (newStatus) => {
    if (newStatus) {
      sendGetStatusData('switch')
    }
  },
  { immediate: true }
)
</script>

<style lang="less" scoped></style>
